### Customize Block Rendering in Lexical Editor

Source: https://github.com/payloadcms/payload/blob/main/docs/fields/blocks.mdx

Explains how to customize the rendering of blocks within the Lexical rich text editor in Payload CMS. This involves providing custom React components for block labels (`admin.components.Label`) and the entire block (`admin.components.Block`) to create a tailored editing experience.

```typescript
import type { Field } from 'payload'

export const MyLexicalBlockField: Field = {
  name: 'myLexicalBlock',
  type: 'blocks',
  blocks: [
    // ... other blocks
    {
      slug: 'gallery',
      labels: {
        singular: 'Gallery',
        plural: 'Galleries',
      },
      admin: {
        components: {
          Label: ({ value }) => <div>Custom Gallery Label: {value.title}</div>,
          Block: ({ children }) => <div style={{ border: '2px solid blue' }}>{children}</div>,
        },
      },
      fields: [
        // ... gallery fields
      ],
    },
  ],
  admin: {
    components: {
      Label: ({ value }) => <span>Custom Block Label: {value.name}</span>,
      Block: ({ children }) => <div>{children}</div>,
    },
  },
}
```

